import React, { createContext, useState, useContext, useEffect } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [token, setToken] = useState(localStorage.getItem('token'));
  const navigate = useNavigate();

  // Set axios default header when token changes
  useEffect(() => {
    if (token) {
      axios.defaults.headers.common['Authorization'] = `Bearer ${token}`;
      console.log('âś… Token set in axios headers');
    } else {
      delete axios.defaults.headers.common['Authorization'];
    }
  }, [token]);

  // Fetch user data if token exists
  useEffect(() => {
    const fetchUser = async () => {
      if (!token) {
        setLoading(false);
        return;
      }

      try {
        console.log('đź”Ť Fetching user data with token...');
        const response = await axios.get(`${API_URL}/auth/me`);
        console.log('âś… User data fetched:', response.data);
        setUser(response.data.user || response.data);
      } catch (error) {
        console.error('âťŚ Error fetching user:', error.response?.data || error.message);
        // If token is invalid, clear it
        localStorage.removeItem('token');
        setToken(null);
        delete axios.defaults.headers.common['Authorization'];
      } finally {
        setLoading(false);
      }
    };

    fetchUser();
  }, [token]);

  const login = async (email, password) => {
    setError(null);
    console.log('đź”‘ Attempting login for:', email);
    console.log('đź“Ť API URL:', `${API_URL}/auth/login`);
    
    try {
      const response = await axios.post(`${API_URL}/auth/login`, { 
        email, 
        password 
      }, {
        headers: {
          'Content-Type': 'application/json'
        }
      });
      
      console.log('âś… Login response:', response.data);
      
      const { token, user } = response.data;
      
      // Save token to localStorage
      localStorage.setItem('token', token);
      setToken(token);
      setUser(user);
      
      // Show success message
      console.log('đźŽ‰ Login successful! Redirecting...');
      
      // Redirect based on role
      if (user.role === 'admin') {
        navigate('/admin/dashboard');
      } else {
        navigate('/customer/dashboard');
      }
      
      return { success: true, user };
    } catch (error) {
      console.error('âťŚ Login error:', error.response?.data || error.message);
      
      let errorMessage = 'Login failed';
      if (error.response?.data?.error) {
        errorMessage = error.response.data.error;
      } else if (error.response?.data?.message) {
        errorMessage = error.response.data.message;
      } else if (error.message) {
        errorMessage = error.message;
      }
      
      setError(errorMessage);
      return { success: false, error: errorMessage };
    }
  };

  const register = async (userData) => {
    setError(null);
    console.log('đź“ť Attempting registration for:', userData.email);
    
    try {
      const response = await axios.post(`${API_URL}/auth/register`, userData, {
        headers: {
          'Content-Type': 'application/json'
        }
      });
      
      console.log('âś… Registration response:', response.data);
      navigate('/login');
      return { success: true };
    } catch (error) {
      console.error('âťŚ Registration error:', error.response?.data || error.message);
      
      let errorMessage = 'Registration failed';
      if (error.response?.data?.error) {
        errorMessage = error.response.data.error;
      } else if (error.response?.data?.message) {
        errorMessage = error.response.data.message;
      } else if (error.message) {
        errorMessage = error.message;
      }
      
      setError(errorMessage);
      return { success: false, error: errorMessage };
    }
  };

  const logout = () => {
    console.log('đź‘‹ Logging out...');
    localStorage.removeItem('token');
    setToken(null);
    setUser(null);
    delete axios.defaults.headers.common['Authorization'];
    navigate('/login');
  };

  const acceptTerms = async (termsId) => {
    try {
      const response = await axios.post(`${API_URL}/terms/accept`, { terms_id: termsId });
      setUser({ ...user, terms_accepted: true });
      return { success: true };
    } catch (error) {
      console.error('âťŚ Error accepting terms:', error);
      return { success: false };
    }
  };

  const value = {
    user,
    loading,
    error,
    login,
    register,
    logout,
    acceptTerms,
    isAuthenticated: !!user,
    isAdmin: user?.role === 'admin'
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};
